function proximoMiercoles() {
  const hoy=new Date(),diff=(3-hoy.getDay()+7)%7||7,d=new Date(hoy);
  d.setDate(hoy.getDate()+diff);
  return d.toLocaleDateString("es-ES",{weekday:"long",day:"numeric",month:"long"});
}
function normalizeEstado(e) {
  if(!e) return "";
  return e;
}
function getMeta(e) { return ESTADO_META[e]||{bg:"#F1F5F9",text:"#334155",dot:"#94A3B8"}; }
function getProgress(e) { return ESTADO_PROGRESS[e]||0; }

function Label({children,required}) {
  return <div style={{fontSize:12,fontWeight:700,color:C.navy,marginBottom:6,textTransform:"uppercase",letterSpacing:"0.05em"}}>{children}{required&&<span style={{color:"#EF4444",marginLeft:3}}>*</span>}</div>;
}
function Input({value,onChange,placeholder,type="text"}) {
  return <input type={type} value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder} style={{width:"100%",padding:"9px 12px",fontSize:13,color:C.text,border:"1px solid "+C.border,borderRadius:8,outline:"none",background:C.bgCard,boxSizing:"border-box"}}/>;
}
function TextArea({value,onChange,placeholder,rows=3}) {
  return <textarea value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder} rows={rows} style={{width:"100%",padding:"9px 12px",fontSize:13,color:C.text,border:"1px solid "+C.border,borderRadius:8,outline:"none",background:C.bgCard,resize:"vertical",boxSizing:"border-box",fontFamily:"inherit"}}/>;
}
function Select({value,onChange,options,placeholder}) {
  return (
    <select value={value} onChange={e=>onChange(e.target.value)} style={{width:"100%",padding:"9px 12px",fontSize:13,color:value?C.text:C.textSub,border:"1px solid "+C.border,borderRadius:8,outline:"none",background:C.bgCard,boxSizing:"border-box"}}>
      <option value="">{placeholder}</option>
      {options.map(o=><option key={o} value={o}>{o}</option>)}
    </select>
  );
}
function PillFilter({label,active,onClick}) {
  return <button onClick={onClick} style={{background:active?C.navy:C.bgCard,color:active?"#FFFFFF":C.textSub,border:"1px solid "+(active?C.navy:C.border),borderRadius:999,fontSize:12,fontWeight:600,padding:"5px 14px",cursor:"pointer",whiteSpace:"nowrap"}}>{label}</button>;
}
function EstadoBadge({estado}) {
  const m=getMeta(estado);
  return <span style={{display:"inline-flex",alignItems:"center",gap:5,background:m.bg,color:m.text,borderRadius:999,fontSize:11,fontWeight:700,padding:"3px 10px"}}><span style={{width:6,height:6,borderRadius:"50%",background:m.dot,flexShrink:0}}/>{ESTADO_DISPLAY[estado]||estado}</span>;
}
function MiniProgress({estado}) {
  const pct=getProgress(estado),m=getMeta(estado);
  const r=9,sw=2.5,circ=2*Math.PI*(r-sw/2),dash=(pct/100)*circ;
  return (
    <svg width={r*2} height={r*2} style={{flexShrink:0}}>
      <circle cx={r} cy={r} r={r-sw/2} fill="none" stroke="#E2E8F0" strokeWidth={sw}/>
      <circle cx={r} cy={r} r={r-sw/2} fill="none" stroke={m.dot} strokeWidth={sw} strokeDasharray={dash+" "+(circ-dash)} strokeLinecap="round" transform={"rotate(-90 "+r+" "+r+")"}/>
    </svg>
  );
}

function InformeCierreModal({piloto,onClose}) {
  const isOK=piloto.estado==="Cierre - OK";
  const isKO=piloto.estado==="Cierre - KO";
  const c=piloto.cierre||{};
  const om=OWNER_META[piloto.owner]||{bg:"#F1F5F9",text:"#334155",icon:"?"};
  const accentBg=isOK?"#F0FDF4":isKO?"#FEF2F2":"#F9FAFB";
  const accentBorder=isOK?"#86EFAC":isKO?"#FCA5A5":"#D1D5DB";
  const accentText=isOK?"#166534":isKO?"#991B1B":"#374151";
  const accentDot=isOK?"#22C55E":isKO?"#EF4444":"#9CA3AF";
  const tipoLabel=isOK?"Cierre - OK":isKO?"Cierre - KO":"Cancelado";

  const Field=({label,value,full})=>{
    if(!value)return null;
    return (
      <div style={{gridColumn:full?"1/-1":"auto",background:"#F8FAFC",borderRadius:10,padding:"14px 16px",border:"1px solid "+C.border}}>
        <div style={{fontSize:10,color:C.textSub,fontWeight:700,textTransform:"uppercase",letterSpacing:"0.06em",marginBottom:6}}>{label}</div>
        <div style={{fontSize:13,color:C.text,lineHeight:1.6}}>{value}</div>
      </div>
    );
  };

  return (
    <CenteredModal onClose={onClose} width={680}>
      <div style={{background:C.navy,padding:"20px 28px 18px",flexShrink:0}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
          <div>
            <div style={{fontSize:11,color:"rgba(255,255,255,0.55)",fontWeight:600,marginBottom:4}}>{"#"+piloto.id+" - Informe de cierre"}</div>
            <div style={{fontSize:20,fontWeight:800,color:"#FFFFFF"}}>{piloto.nombre}</div>
          </div>
          <button onClick={onClose} style={{background:"rgba(255,255,255,0.12)",border:"none",color:"#FFFFFF",borderRadius:8,width:32,height:32,fontSize:16,cursor:"pointer"}}>X</button>
        </div>
        <div style={{display:"flex",gap:8,marginTop:12,flexWrap:"wrap"}}>
          <span style={{display:"inline-flex",alignItems:"center",gap:5,background:accentBg,color:accentText,borderRadius:999,fontSize:11,fontWeight:700,padding:"3px 10px",border:"1px solid "+accentBorder}}>
            <span style={{width:6,height:6,borderRadius:"50%",background:accentDot}}/>
            {tipoLabel}
          </span>
          <span style={{display:"inline-flex",alignItems:"center",gap:5,background:om.bg,color:om.text,borderRadius:999,fontSize:11,fontWeight:700,padding:"3px 10px"}}>{om.icon+" "+piloto.owner}</span>
          {piloto.institucion&&<span style={{background:"rgba(255,255,255,0.15)",color:"white",borderRadius:999,fontSize:11,fontWeight:600,padding:"3px 10px"}}>{piloto.institucion}</span>}
          {c.fecha&&<span style={{background:"rgba(255,255,255,0.1)",color:"rgba(255,255,255,0.7)",borderRadius:999,fontSize:11,fontWeight:500,padding:"3px 10px"}}>{"Cerrado el "+c.fecha}</span>}
        </div>
      </div>
      <div style={{flex:1,overflowY:"auto",padding:"24px 28px",display:"flex",flexDirection:"column",gap:16}}>
        {!piloto.cierre ? (
          <div style={{background:"#FFF7ED",border:"1px solid #FDE68A",borderRadius:12,padding:"20px",textAlign:"center"}}>
            <div style={{fontSize:14,fontWeight:700,color:"#92400E",marginBottom:6}}>Informe no disponible</div>
            <div style={{fontSize:13,color:C.textSub}}>Este piloto fue cerrado sin registrar un informe de cierre detallado.</div>
          </div>
        ) : (
          <>
            <div style={{background:accentBg,border:"1.5px solid "+accentBorder,borderRadius:12,padding:"16px 20px",display:"flex",alignItems:"center",gap:14}}>
              <span style={{fontSize:28}}>{isOK?"✅":isKO?"❌":"⏸️"}</span>
              <div>
                <div style={{fontSize:14,fontWeight:800,color:accentText}}>{tipoLabel}</div>
                {c.decision&&<div style={{fontSize:12,color:accentText,opacity:0.8,marginTop:2}}>{"Decision: "+c.decision}</div>}
              </div>
            </div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
              {c.validacionHipotesis&&(
                <div style={{background:"#F8FAFC",borderRadius:10,padding:"14px 16px",border:"1px solid "+C.border}}>
                  <div style={{fontSize:10,color:C.textSub,fontWeight:700,textTransform:"uppercase",letterSpacing:"0.06em",marginBottom:6}}>Hipotesis validada</div>
                  <span style={{display:"inline-flex",alignItems:"center",gap:5,background:c.validacionHipotesis==="Si"?"#F0FDF4":c.validacionHipotesis==="No"?"#FEF2F2":"#FFFBEB",color:c.validacionHipotesis==="Si"?"#166534":c.validacionHipotesis==="No"?"#991B1B":"#92400E",borderRadius:999,fontSize:13,fontWeight:700,padding:"4px 14px",border:"1.5px solid "+(c.validacionHipotesis==="Si"?"#86EFAC":c.validacionHipotesis==="No"?"#FCA5A5":"#FDE68A")}}>
                    {c.validacionHipotesis==="Si"?"✓ Sí":c.validacionHipotesis==="No"?"✗ No":"~ Parcialmente"}
                  </span>
                  {piloto.hipotesis&&<div style={{fontSize:11,color:C.textSub,marginTop:8,lineHeight:1.5,fontStyle:"italic"}}>{"«"+piloto.hipotesis+"»"}</div>}
                </div>
              )}
              <Field label="Decision tomada" value={c.decision}/>
              <Field label="Consecucion de objetivos" value={c.objetivos} full/>
              <Field label="Alcance conseguido" value={c.alcanceConseguido} full/>
              <Field label="Resumen ejecutivo" value={c.resumen} full/>
            </div>
            <div style={{background:"#F8FAFC",borderRadius:10,padding:"14px 16px",border:"1px solid "+C.border}}>
              <div style={{fontSize:10,color:C.textSub,fontWeight:700,textTransform:"uppercase",letterSpacing:"0.06em",marginBottom:8}}>Datos del piloto</div>
              <div style={{display:"flex",gap:24,flexWrap:"wrap"}}>
                {piloto.inicio&&<div><span style={{fontSize:11,color:C.textSub}}>Inicio: </span><span style={{fontSize:12,fontWeight:600,color:C.text}}>{piloto.inicio}</span></div>}
                {piloto.fin&&<div><span style={{fontSize:11,color:C.textSub}}>Fin previsto: </span><span style={{fontSize:12,fontWeight:600,color:C.text}}>{piloto.fin}</span></div>}
                {c.fecha&&<div><span style={{fontSize:11,color:C.textSub}}>Fecha cierre: </span><span style={{fontSize:12,fontWeight:600,color:C.text}}>{c.fecha}</span></div>}
                {piloto.kpis&&<div style={{width:"100%"}}><span style={{fontSize:11,color:C.textSub}}>KPIs: </span><span style={{fontSize:12,fontWeight:600,color:C.text}}>{piloto.kpis}</span></div>}
              </div>
            </div>
          </>
        )}
      </div>
      <div style={{padding:"14px 28px",borderTop:"1px solid "+C.border,display:"flex",justifyContent:"flex-end",flexShrink:0}}>
        <button onClick={onClose} style={{background:C.navy,color:"#FFFFFF",border:"none",borderRadius:8,padding:"9px 24px",fontSize:13,fontWeight:700,cursor:"pointer"}}>Cerrar</button>
      </div>
    </CenteredModal>
  );
}

function SidePanel({onClose,width=460,headerBg=C.navy,headerContent,children,footerContent}) {
  return (
    <div style={{position:"fixed",inset:0,zIndex:1000,display:"flex",justifyContent:"flex-end"}}>
      <div style={{position:"absolute",inset:0,background:"rgba(0,30,60,0.35)"}} onClick={onClose}/>
      <div style={{position:"relative",width:width,maxWidth:"95vw",background:C.bgCard,boxShadow:"-8px 0 40px rgba(0,0,0,0.18)",display:"flex",flexDirection:"column"}}>
        <style>{`@keyframes slideIn{from{transform:translateX(100%)}to{transform:translateX(0)}} @keyframes popIn{from{transform:scale(0.95);opacity:0}to{transform:scale(1);opacity:1}}`}</style>
        <div style={{background:headerBg,flexShrink:0}}>{headerContent}</div>
        <div style={{flex:1,overflowY:"auto"}}>{children}</div>
        {footerContent&&<div style={{borderTop:"1px solid "+C.border,background:C.bgCard,flexShrink:0}}>{footerContent}</div>}
      </div>
    </div>
  );
}

function CenteredModal({onClose,width=720,children}) {
  return (
    <div style={{position:"fixed",inset:0,zIndex:1000,display:"flex",alignItems:"center",justifyContent:"center"}}>
      <div style={{position:"absolute",inset:0,background:"rgba(0,30,60,0.45)"}} onClick={onClose}/>
      <div style={{position:"relative",width:width,maxWidth:"95vw",maxHeight:"92vh",background:C.bgCard,borderRadius:16,boxShadow:"0 24px 64px rgba(0,0,0,0.22)",display:"flex",flexDirection:"column",overflow:"hidden"}}>
        {children}
      </div>
    </div>
  );
}

function PilotCard({p,onDetail,onInforme}) {
  const [hov,setHov]=useState(false),[btnHov,setBtnHov]=useState(false),[btn2Hov,setBtn2Hov]=useState(false);
  const om=OWNER_META[p.owner]||{bg:"#F1F5F9",text:"#334155",icon:"?"};
  const showInforme=p.estado==="Cierre - OK"||p.estado==="Cierre - KO";
  const isOK=p.estado==="Cierre - OK";
  const informeColor=isOK?"#166534":"#991B1B";
  const informeBg=isOK?"#F0FDF4":"#FEF2F2";
  const informeBgHov=isOK?"#dcfce7":"#fee2e2";
  return (
    <div onMouseEnter={()=>setHov(true)} onMouseLeave={()=>setHov(false)} style={{background:C.bgCard,borderRadius:14,border:"1px solid "+(hov?C.blue+"66":C.border),boxShadow:hov?"0 12px 32px rgba(0,51,102,0.14)":"0 2px 8px rgba(0,0,0,0.06)",overflow:"hidden",display:"flex",flexDirection:"column",transition:"box-shadow 0.2s,border-color 0.2s,transform 0.15s",transform:hov?"translateY(-3px)":"translateY(0)"}}>
      <div style={{height:4,background:"linear-gradient(90deg,"+C.navy+","+C.blue+")",opacity:hov?1:0.35,transition:"opacity 0.2s"}}/>
      <div style={{padding:"16px 16px 12px",flex:1,display:"flex",flexDirection:"column",gap:10}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",gap:8}}>
          <div style={{fontSize:14,fontWeight:800,color:C.navy,lineHeight:1.3}}>{p.nombre}</div>
          <span style={{fontSize:11,fontWeight:700,color:C.textSub,background:"#F1F5F9",borderRadius:6,padding:"2px 8px",whiteSpace:"nowrap",flexShrink:0}}>{"#"+p.id}</span>
        </div>
        <div style={{display:"flex",alignItems:"center",gap:6}}>
          <MiniProgress estado={p.estado}/>
          <EstadoBadge estado={p.estado}/>
        </div>
        <div style={{display:"flex",alignItems:"center",gap:6,flexWrap:"wrap"}}>
          <span style={{display:"inline-flex",alignItems:"center",gap:5,background:om.bg,color:om.text,borderRadius:999,fontSize:12,fontWeight:700,padding:"3px 12px",border:"1px solid "+om.text+"22"}}>
            <span>{om.icon}</span>{p.owner}
          </span>
          {(p.equipo||[]).slice(0,2).map(e=>{const xm=OWNER_META[e]||{bg:"#F1F5F9",text:"#334155",icon:"?"};return <span key={e} style={{display:"inline-flex",alignItems:"center",gap:4,background:xm.bg,color:xm.text,borderRadius:999,fontSize:11,fontWeight:600,padding:"2px 9px",border:"1px solid "+xm.text+"22"}}><span>{xm.icon}</span>{e}</span>;})}
          {(p.equipo||[]).length>2&&<span style={{fontSize:11,color:C.textSub}}>{"+"+(p.equipo.length-2)}</span>}
        </div>
        <div style={{marginTop:"auto",paddingTop:8,borderTop:"1px solid "+C.border}}>
          <div style={{fontSize:12,color:C.textSub,fontWeight:500}}>{p.agrupador+" - "+p.institucion}</div>
          <div style={{fontSize:11,color:"#94A3B8",marginTop:2}}>{p.inicio+(p.fin?" - "+p.fin:"")}</div>
        </div>
      </div>
      <div style={{borderTop:"1px solid "+C.border,display:"flex"}}>
        <button onMouseEnter={()=>setBtnHov(true)} onMouseLeave={()=>setBtnHov(false)} onClick={()=>onDetail(p)} style={{background:btnHov?C.blue:"transparent",color:btnHov?"#FFFFFF":C.blue,border:"none",padding:"10px 16px",fontSize:12,fontWeight:700,cursor:"pointer",flex:1,transition:"background 0.15s,color 0.15s"}}>Ver detalles</button>
        {showInforme&&(
          <>
            <div style={{width:1,background:C.border}}/>
            <button onMouseEnter={()=>setBtn2Hov(true)} onMouseLeave={()=>setBtn2Hov(false)} onClick={()=>onInforme(p)} style={{background:btn2Hov?informeBgHov:informeBg,color:informeColor,border:"none",padding:"10px 16px",fontSize:12,fontWeight:700,cursor:"pointer",flex:1,transition:"background 0.15s",whiteSpace:"nowrap"}}>Ver informe</button>
          </>
        )}
      </div>
    </div>
  );
}

function InfoBlock({label,value}) {
  return <div><div style={{fontSize:10,color:C.textSub,fontWeight:700,textTransform:"uppercase",letterSpacing:"0.06em",marginBottom:4}}>{label}</div><div style={{fontSize:13,color:C.text,lineHeight:1.5}}>{value}</div></div>;
}

function CierreInforme({cierre,estado}) {
  const isOK=estado==="Cierre - OK";
  return (
    <div style={{border:"1.5px solid "+(isOK?"#86EFAC":"#FCA5A5"),borderRadius:12,overflow:"hidden"}}>
      <div style={{background:isOK?"#F0FDF4":"#FEF2F2",padding:"10px 16px",display:"flex",alignItems:"center",gap:8}}>
        <span style={{fontSize:13,fontWeight:800,color:isOK?C.green:C.red}}>{"Informe de Cierre - "+(isOK?"GO":"NO GO")}</span>
        <span style={{fontSize:11,color:C.textSub,marginLeft:"auto"}}>{cierre.fecha}</span>
      </div>
      <div style={{padding:"14px 16px",display:"flex",flexDirection:"column",gap:10}}>
        <InfoBlock label="Resultado" value={cierre.resultado}/>
        {cierre.decision&&<InfoBlock label="Decision" value={cierre.decision}/>}
        {cierre.resumen&&<InfoBlock label="Resumen ejecutivo" value={cierre.resumen}/>}
      </div>
    </div>
  );
}

function DetailPanel({piloto,onClose,onCerrar,onUpdate}) {
  const [editMode,setEditMode]=useState(false);
  const initInst=piloto.institucion?piloto.institucion.split(", ").filter(Boolean):[];
  const [ef,setEf]=useState({estado:piloto.estado,nextSteps:piloto.nextSteps,instituciones:initInst,inicio:piloto.inicio,fin:piloto.fin});
  const [instSearch,setInstSearch]=useState("");
  const [instOpen,setInstOpen]=useState(false);
  const instRef=useRef(null);
  useEffect(()=>{
    const h=e=>{if(instRef.current&&!instRef.current.contains(e.target))setInstOpen(false);};
    document.addEventListener("mousedown",h);
    return ()=>document.removeEventListener("mousedown",h);
  },[]);
  const setE=(k,v)=>setEf(f=>({...f,[k]:v}));
  const toDate=s=>s?s.split("/").reverse().join("-"):"";
  const fromDate=s=>s?s.split("-").reverse().join("/"):"";
  const filteredInstEdit=INSTITUCIONES_ALL.filter(i=>i.toLowerCase().includes(instSearch.toLowerCase()));
  const toggleInstEdit=inst=>setEf(f=>({...f,instituciones:f.instituciones.includes(inst)?f.instituciones.filter(x=>x!==inst):[...f.instituciones,inst]}));
  const estadoActual=editMode?ef.estado:piloto.estado;
  const pct=getProgress(estadoActual);
  const em=getMeta(estadoActual);
  const om=OWNER_META[piloto.owner]||{bg:"#F1F5F9",text:"#334155",icon:"?"};
  const puedesCerrar=!editMode&&!["Cierre - OK","Cierre - KO","Cancelado","Rechazado Comite"].includes(piloto.estado);
  const yaCerrado=["Cierre - OK","Cierre - KO","Cancelado","Rechazado Comite"].includes(piloto.estado);
  const ciclo=["Pendiente aprobacion","Analisis","Desarrollo","Evaluacion","Cierre"];
  const esCierre=["Cierre - OK","Cierre - KO","Cierre - Stand By"].includes(estadoActual);
  const estadoNorm=esCierre?"Cierre":estadoActual;
  const hitoActivo=ciclo.indexOf(estadoNorm);

  return (
    <SidePanel onClose={onClose} width={420}
      headerContent={
        <div style={{padding:"20px 24px 16px"}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
            <div>
              <div style={{fontSize:11,color:"rgba(255,255,255,0.55)",fontWeight:600,marginBottom:4}}>{"#"+piloto.id+(piloto.agrupador?" - "+piloto.agrupador:"")}</div>
              <div style={{fontSize:17,fontWeight:800,color:"#FFFFFF",lineHeight:1.3}}>{piloto.nombre}</div>
            </div>
            <button onClick={onClose} style={{background:"rgba(255,255,255,0.12)",border:"none",color:"#FFFFFF",borderRadius:8,width:30,height:30,fontSize:16,cursor:"pointer",flexShrink:0}}>X</button>
          </div>
          <div style={{display:"flex",gap:8,marginTop:12,flexWrap:"wrap"}}>
            <EstadoBadge estado={estadoActual}/>
            <span style={{display:"inline-flex",alignItems:"center",gap:5,background:om.bg,color:om.text,borderRadius:999,fontSize:11,fontWeight:700,padding:"3px 10px"}}>{om.icon+" "+piloto.owner}</span>
          </div>
        </div>
      }
      footerContent={
        <div style={{padding:"14px 24px",display:"flex",gap:10,justifyContent:"space-between",alignItems:"center"}}>
          <div style={{display:"flex",gap:8}}>
            {!yaCerrado&&!editMode&&<button onClick={()=>setEditMode(true)} style={{background:"transparent",color:C.blue,border:"1px solid "+C.blue,borderRadius:8,padding:"9px 16px",fontSize:13,fontWeight:700,cursor:"pointer"}}>Editar</button>}
            {editMode&&(
              <div style={{display:"flex",gap:8}}>
                <button onClick={()=>setEditMode(false)} style={{background:"transparent",color:C.textSub,border:"1px solid "+C.border,borderRadius:8,padding:"9px 16px",fontSize:13,fontWeight:600,cursor:"pointer"}}>Cancelar</button>
                <button onClick={()=>{onUpdate(piloto.id,{...ef,institucion:ef.instituciones.join(", ")});setEditMode(false);}} style={{background:C.navy,color:"#FFFFFF",border:"none",borderRadius:8,padding:"9px 20px",fontSize:13,fontWeight:700,cursor:"pointer"}}>Guardar</button>
              </div>
            )}
          </div>
          <div style={{display:"flex",gap:8}}>
            {puedesCerrar&&<button onClick={()=>onCerrar(piloto)} style={{background:C.navy,color:"#FFFFFF",border:"none",borderRadius:8,padding:"9px 20px",fontSize:13,fontWeight:700,cursor:"pointer"}}>Cerrar piloto</button>}
            {yaCerrado&&piloto.cierre&&<div style={{fontSize:12,color:C.textSub,alignSelf:"center"}}>{"Cerrado el "+piloto.cierre.fecha}</div>}
          </div>
        </div>
      }
    >
      <div style={{padding:"20px 24px",display:"flex",flexDirection:"column",gap:16}}>
        <div>
          <div style={{display:"flex",justifyContent:"space-between",marginBottom:6}}>
            <span style={{fontSize:12,fontWeight:700,color:C.navy}}>Progreso</span>
            <span style={{fontSize:13,fontWeight:800,color:em.dot}}>{pct+"%"}</span>
          </div>
          <div style={{background:"#E2E8F0",borderRadius:999,height:10}}>
            <div style={{width:pct+"%",background:"linear-gradient(90deg,"+C.navy+","+C.blue+")",borderRadius:999,height:10}}/>
          </div>
        </div>
        <div>
          <div style={{fontSize:12,fontWeight:700,color:C.navy,marginBottom:12}}>Ciclo de vida</div>
          {ciclo.map((h,i)=>{
            const done=i<hitoActivo,active=i===hitoActivo;
            const dc=active?(esCierre&&h==="Cierre"?(piloto.estado==="Cierre - OK"?"#22C55E":piloto.estado==="Cierre - KO"?"#EF4444":"#9CA3AF"):C.blue):done?C.navy:"#E2E8F0";
            const lbl=active&&esCierre?piloto.estado:h;
            return (
              <div key={h} style={{display:"flex",gap:12}}>
                <div style={{display:"flex",flexDirection:"column",alignItems:"center"}}>
                  <div style={{width:22,height:22,borderRadius:"50%",flexShrink:0,background:dc,display:"flex",alignItems:"center",justifyContent:"center",fontSize:10,color:"#FFFFFF",fontWeight:800,boxShadow:active?"0 0 0 4px "+dc+"33":"none"}}>{done?"v":i+1}</div>
                  {i<ciclo.length-1&&<div style={{width:2,height:24,background:done?C.navy:"#E2E8F0",margin:"2px 0"}}/>}
                </div>
                <div style={{paddingTop:2,paddingBottom:i<ciclo.length-1?20:0}}>
                  <div style={{fontSize:13,fontWeight:active?700:500,color:done||active?C.navy:C.textSub}}>{lbl}</div>
                  {active&&<span style={{fontSize:10,background:dc+"20",color:dc,borderRadius:999,padding:"1px 8px",fontWeight:600}}>En curso</span>}
                </div>
              </div>
            );
          })}
        </div>
        {editMode&&(
          <div style={{background:"#F0F6FF",border:"1px solid #BFDBFE",borderRadius:12,padding:"16px"}}>
            <div style={{fontSize:12,fontWeight:700,color:C.navy,marginBottom:14}}>Modo edicion</div>
            <div style={{marginBottom:14}}>
              <Label>Estado</Label>
              <div style={{display:"flex",flexWrap:"wrap",gap:6,marginTop:4}}>
                {ESTADOS_EDIT.map(s=>{const m=getMeta(s),act=ef.estado===s;return <button key={s} onClick={()=>setE("estado",s)} style={{display:"inline-flex",alignItems:"center",gap:5,background:act?m.bg:C.bgCard,color:act?m.text:C.textSub,border:"1.5px solid "+(act?m.dot:C.border),borderRadius:999,fontSize:12,fontWeight:600,padding:"5px 12px",cursor:"pointer"}}><span style={{width:6,height:6,borderRadius:"50%",background:act?m.dot:"#D1D5DB",flexShrink:0}}/>{s}</button>;})}
              </div>
            </div>
            <div style={{marginBottom:14}}><Label>Next steps</Label><TextArea value={ef.nextSteps} onChange={v=>setE("nextSteps",v)} placeholder="Proximos pasos..." rows={3}/></div>
            <div style={{marginBottom:14}}>
              <Label>Instituciones</Label>
              {ef.instituciones.length>0&&(
                <div style={{display:"flex",flexWrap:"wrap",gap:6,marginBottom:8}}>
                  {ef.instituciones.map(inst=>(
                    <span key={inst} style={{display:"inline-flex",alignItems:"center",gap:5,background:"#EFF6FF",color:"#1E40AF",border:"1px solid #BFDBFE",borderRadius:999,fontSize:12,fontWeight:600,padding:"3px 10px"}}>
                      {inst}<span onMouseDown={e=>{e.preventDefault();toggleInstEdit(inst);}} style={{cursor:"pointer",fontSize:13,fontWeight:800,marginLeft:2}}>x</span>
                    </span>
                  ))}
                </div>
              )}
              <div ref={instRef} style={{position:"relative"}}>
                <div onClick={()=>setInstOpen(o=>!o)} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"9px 12px",border:"1px solid "+(instOpen?C.blue:C.border),borderRadius:8,cursor:"pointer",background:C.bgCard,fontSize:13,color:C.textSub}}>
                  <span>{ef.instituciones.length?(ef.instituciones.length+" seleccionada"+(ef.instituciones.length>1?"s":"")):"Selecciona..."}</span>
                  <span>{instOpen?"v":">"}</span>
                </div>
                {instOpen&&(
                  <div style={{position:"absolute",top:"calc(100% + 4px)",left:0,right:0,background:C.bgCard,border:"1px solid "+C.border,borderRadius:10,boxShadow:"0 12px 32px rgba(0,0,0,0.18)",zIndex:3000,overflow:"hidden"}}>
                    <div style={{padding:"8px"}}><input autoFocus value={instSearch} onChange={e=>setInstSearch(e.target.value)} placeholder="Buscar..." style={{width:"100%",padding:"7px 10px",fontSize:13,border:"1px solid "+C.border,borderRadius:6,outline:"none",boxSizing:"border-box"}}/></div>
                    <div style={{maxHeight:180,overflowY:"auto"}}>
                      {filteredInstEdit.map(inst=>(
                        <div key={inst} onMouseDown={e=>{e.preventDefault();toggleInstEdit(inst);}} style={{display:"flex",alignItems:"center",gap:10,padding:"8px 14px",cursor:"pointer",background:ef.instituciones.includes(inst)?"#EFF6FF":"transparent",borderBottom:"1px solid "+C.border}}>
                          <div style={{width:16,height:16,borderRadius:4,border:"2px solid "+(ef.instituciones.includes(inst)?C.blue:C.border),background:ef.instituciones.includes(inst)?C.blue:"transparent",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
                            {ef.instituciones.includes(inst)&&<span style={{color:"#fff",fontSize:10,fontWeight:800}}>v</span>}
                          </div>
                          <span style={{fontSize:13,color:ef.instituciones.includes(inst)?C.blue:C.text}}>{inst}</span>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            </div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
              <div><Label>Fecha inicio</Label><Input type="date" value={toDate(ef.inicio)} onChange={v=>setE("inicio",fromDate(v))}/></div>
              <div><Label>Fecha fin</Label><Input type="date" value={toDate(ef.fin)} onChange={v=>setE("fin",fromDate(v))}/></div>
            </div>
          </div>
        )}
        <div style={{background:"#F8FAFC",borderRadius:10,padding:"14px 16px",border:"1px solid "+C.border}}>
          <div style={{fontSize:10,color:C.textSub,fontWeight:700,textTransform:"uppercase",letterSpacing:"0.06em",marginBottom:6}}>Objetivo</div>
          <div style={{fontSize:13,color:C.text,lineHeight:1.6}}>{piloto.objetivo}</div>
        </div>
        <div style={{background:"#F8FAFC",borderRadius:10,padding:"14px 16px",border:"1px solid "+C.border}}>
          <div style={{fontSize:10,color:C.textSub,fontWeight:700,textTransform:"uppercase",letterSpacing:"0.06em",marginBottom:6}}>KPIs</div>
          <div style={{fontSize:13,color:C.text}}>{piloto.kpis}</div>
        </div>
        <div style={{background:"#FFFBEB",borderRadius:10,padding:"14px 16px",border:"1px solid #FDE68A"}}>
          <div style={{fontSize:10,color:"#92400E",fontWeight:700,textTransform:"uppercase",letterSpacing:"0.06em",marginBottom:6}}>Next steps</div>
          <div style={{fontSize:13,color:C.text}}>{editMode?ef.nextSteps:piloto.nextSteps}</div>
        </div>
        {yaCerrado&&piloto.cierre&&<CierreInforme cierre={piloto.cierre} estado={piloto.estado}/>}

        {(piloto.historial||[]).length>0&&(
          <div>
            <div style={{fontSize:12,fontWeight:700,color:C.navy,marginBottom:10}}>Historial de cambios</div>
            <div style={{display:"flex",flexDirection:"column",gap:0}}>
              {[...(piloto.historial||[])].reverse().map((h,i)=>(
                <div key={i} style={{display:"flex",gap:12,paddingBottom:12}}>
                  <div style={{display:"flex",flexDirection:"column",alignItems:"center"}}>
                    <div style={{width:10,height:10,borderRadius:"50%",background:C.border,flexShrink:0,marginTop:3}}/>
                    {i<(piloto.historial||[]).length-1&&<div style={{width:1,flex:1,background:C.border,margin:"3px 0"}}/>}
                  </div>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:11,color:C.textSub,marginBottom:2}}>{h.fecha}</div>
                    <div style={{fontSize:12,color:C.text,lineHeight:1.5}}>{h.cambio}</div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        <div style={{fontSize:12,color:C.textSub}}>
          <span style={{fontWeight:600}}>Institucion: </span>{editMode?ef.instituciones.join(", "):(piloto.institucion||"--")}
          {" - "}<span style={{fontWeight:600}}>Inicio: </span>{editMode?ef.inicio:piloto.inicio}
          {" - "}<span style={{fontWeight:600}}>Fin: </span>{editMode?ef.fin:(piloto.fin||"--")}
        </div>
      </div>
    </SidePanel>
  );
}

function FichaPopup({piloto,onClose,onUpdate,onAprobar,onRechazar}) {
  const [editMode,setEditMode]=useState(false);
  const [ef,setEf]=useState({objetivo:piloto.objetivo||"",kpis:piloto.kpis||"",hipotesis:piloto.hipotesis||"",alcance:piloto.alcance||"",inicio:piloto.inicio||"",fin:piloto.fin||"",equipo:piloto.equipo||[]});
  const [confirm,setConfirm]=useState(null);
  const setE=(k,v)=>setEf(f=>({...f,[k]:v}));
  const toggleEquipo=e=>setE("equipo",ef.equipo.includes(e)?ef.equipo.filter(x=>x!==e):[...ef.equipo,e]);
  const toDate=s=>s?s.split("/").reverse().join("-"):"";
  const fromDate=s=>s?s.split("-").reverse().join("/"):"";
  const om=OWNER_META[piloto.owner]||{bg:"#F1F5F9",text:"#334155",icon:"?"};

  if(confirm==="aprobar") return (
    <CenteredModal onClose={onClose} width={480}>
      <div style={{background:"#166534",padding:"20px 24px 16px",flexShrink:0}}>
        <div style={{fontSize:17,fontWeight:800,color:"#FFFFFF"}}>Aprobar piloto</div>
        <div style={{fontSize:12,color:"rgba(255,255,255,0.7)",marginTop:4}}>{piloto.nombre}</div>
      </div>
      <div style={{padding:"24px",display:"flex",flexDirection:"column",gap:16}}>
        <div style={{background:"#F0FDF4",border:"1px solid #86EFAC",borderRadius:12,padding:"20px",textAlign:"center"}}>
          <div style={{fontSize:15,fontWeight:800,color:C.green}}>Piloto aprobado por el comite</div>
          <div style={{fontSize:13,color:C.textSub,marginTop:6}}>El piloto pasara al estado Analisis.</div>
        </div>
        <div style={{display:"flex",justifyContent:"space-between",gap:10}}>
          <button onClick={()=>setConfirm(null)} style={{background:"transparent",color:C.textSub,border:"1px solid "+C.border,borderRadius:8,padding:"9px 20px",fontSize:13,fontWeight:600,cursor:"pointer"}}>Cancelar</button>
          <button onClick={()=>{onAprobar(piloto.id);onClose();}} style={{background:C.green,color:"#FFFFFF",border:"none",borderRadius:8,padding:"9px 24px",fontSize:13,fontWeight:700,cursor:"pointer"}}>Confirmar aprobacion</button>
        </div>
      </div>
    </CenteredModal>
  );

  if(confirm==="rechazar") return (
    <CenteredModal onClose={onClose} width={480}>
      <div style={{background:"#991B1B",padding:"20px 24px 16px",flexShrink:0}}>
        <div style={{fontSize:17,fontWeight:800,color:"#FFFFFF"}}>Rechazar piloto</div>
        <div style={{fontSize:12,color:"rgba(255,255,255,0.7)",marginTop:4}}>{piloto.nombre}</div>
      </div>
      <div style={{padding:"24px",display:"flex",flexDirection:"column",gap:16}}>
        <div style={{background:"#FEF2F2",border:"1px solid #FCA5A5",borderRadius:12,padding:"20px",textAlign:"center"}}>
          <div style={{fontSize:15,fontWeight:800,color:C.red}}>Piloto rechazado por el comite</div>
          <div style={{fontSize:13,color:C.textSub,marginTop:6}}>El piloto quedara en estado Rechazado Comite.</div>
        </div>
        <div style={{display:"flex",justifyContent:"space-between",gap:10}}>
          <button onClick={()=>setConfirm(null)} style={{background:"transparent",color:C.textSub,border:"1px solid "+C.border,borderRadius:8,padding:"9px 20px",fontSize:13,fontWeight:600,cursor:"pointer"}}>Cancelar</button>
          <button onClick={()=>{onRechazar(piloto.id);onClose();}} style={{background:C.red,color:"#FFFFFF",border:"none",borderRadius:8,padding:"9px 24px",fontSize:13,fontWeight:700,cursor:"pointer"}}>Confirmar rechazo</button>
        </div>
      </div>
    </CenteredModal>
  );

  return (
    <CenteredModal onClose={onClose} width={720}>
      <div style={{background:C.navy,padding:"20px 28px 18px",flexShrink:0}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
          <div>
            <div style={{fontSize:11,color:"rgba(255,255,255,0.55)",fontWeight:600,marginBottom:4}}>{"#"+piloto.id+" - Ficha de presentacion al comite"}</div>
            <div style={{fontSize:20,fontWeight:800,color:"#FFFFFF"}}>{piloto.nombre}</div>
          </div>
          <button onClick={onClose} style={{background:"rgba(255,255,255,0.12)",border:"none",color:"#FFFFFF",borderRadius:8,width:32,height:32,fontSize:16,cursor:"pointer"}}>X</button>
        </div>
        <div style={{display:"flex",gap:8,marginTop:12,flexWrap:"wrap"}}>
          <EstadoBadge estado={piloto.estado}/>
          <span style={{display:"inline-flex",alignItems:"center",gap:5,background:om.bg,color:om.text,borderRadius:999,fontSize:11,fontWeight:700,padding:"3px 10px"}}>{om.icon+" "+piloto.owner}</span>
          {piloto.institucion&&<span style={{background:"rgba(255,255,255,0.15)",color:"white",borderRadius:999,fontSize:11,fontWeight:600,padding:"3px 10px"}}>{piloto.institucion}</span>}
        </div>
      </div>
      <div style={{flex:1,overflowY:"auto",padding:"24px 28px"}}>
        {editMode ? (
          <div style={{display:"flex",flexDirection:"column",gap:16}}>
            <div><Label required>Objetivo principal</Label><TextArea value={ef.objetivo} onChange={v=>setE("objetivo",v)} rows={3}/></div>
            <div><Label required>Hipotesis a validar</Label><TextArea value={ef.hipotesis} onChange={v=>setE("hipotesis",v)} rows={3}/></div>
            <div><Label required>Alcance del piloto</Label><TextArea value={ef.alcance} onChange={v=>setE("alcance",v)} rows={3}/></div>
            <div><Label required>Metricas y criterios de exito</Label><TextArea value={ef.kpis} onChange={v=>setE("kpis",v)} rows={3}/></div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
              <div><Label>Fecha inicio</Label><Input type="date" value={toDate(ef.inicio)} onChange={v=>setE("inicio",fromDate(v))}/></div>
              <div><Label>Fecha fin</Label><Input type="date" value={toDate(ef.fin)} onChange={v=>setE("fin",fromDate(v))}/></div>
            </div>
            <div>
              <Label>Equipos participantes</Label>
              <div style={{display:"flex",flexWrap:"wrap",gap:8,marginTop:4}}>
                {OWNERS_LIST.filter(o=>o!==piloto.owner).map(o=>{const m=OWNER_META[o]||{bg:"#F1F5F9",text:"#334155",icon:"?"};const active=ef.equipo.includes(o);return <button key={o} onClick={()=>toggleEquipo(o)} style={{display:"inline-flex",alignItems:"center",gap:5,background:active?m.bg:C.bgCard,color:active?m.text:C.textSub,border:"1px solid "+(active?m.text+"44":C.border),borderRadius:999,fontSize:12,fontWeight:600,padding:"4px 12px",cursor:"pointer"}}><span>{m.icon}</span>{o}</button>;})}
              </div>
            </div>
          </div>
        ) : (
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16}}>
            <div style={{background:"#F8FAFC",borderRadius:10,padding:"14px 16px",border:"1px solid "+C.border}}><div style={{fontSize:10,color:C.textSub,fontWeight:700,textTransform:"uppercase",letterSpacing:"0.06em",marginBottom:8}}>Objetivo principal</div><div style={{fontSize:13,color:C.text,lineHeight:1.6}}>{piloto.objetivo||"--"}</div></div>
            <div style={{background:"#F8FAFC",borderRadius:10,padding:"14px 16px",border:"1px solid "+C.border}}><div style={{fontSize:10,color:C.textSub,fontWeight:700,textTransform:"uppercase",letterSpacing:"0.06em",marginBottom:8}}>Metricas y KPIs</div><div style={{fontSize:13,color:C.text,lineHeight:1.6}}>{piloto.kpis||"--"}</div></div>
            {piloto.hipotesis&&<div style={{gridColumn:"1/-1",background:"#F8FAFC",borderRadius:10,padding:"14px 16px",border:"1px solid "+C.border}}><div style={{fontSize:10,color:C.textSub,fontWeight:700,textTransform:"uppercase",letterSpacing:"0.06em",marginBottom:8}}>Hipotesis a validar</div><div style={{fontSize:13,color:C.text,lineHeight:1.6}}>{piloto.hipotesis}</div></div>}
            {piloto.alcance&&<div style={{gridColumn:"1/-1",background:"#F8FAFC",borderRadius:10,padding:"14px 16px",border:"1px solid "+C.border}}><div style={{fontSize:10,color:C.textSub,fontWeight:700,textTransform:"uppercase",letterSpacing:"0.06em",marginBottom:8}}>Alcance del piloto</div><div style={{fontSize:13,color:C.text,lineHeight:1.6}}>{piloto.alcance}</div></div>}
            <div style={{background:"#FFFBEB",borderRadius:10,padding:"14px 16px",border:"1px solid #FDE68A"}}><div style={{fontSize:10,color:"#92400E",fontWeight:700,textTransform:"uppercase",letterSpacing:"0.06em",marginBottom:8}}>Next steps</div><div style={{fontSize:13,color:C.text,lineHeight:1.6}}>{piloto.nextSteps||"--"}</div></div>
            <div style={{background:"#F8FAFC",borderRadius:10,padding:"14px 16px",border:"1px solid "+C.border}}>
              <div style={{fontSize:10,color:C.textSub,fontWeight:700,textTransform:"uppercase",letterSpacing:"0.06em",marginBottom:6}}>Periodo</div>
              <div style={{fontSize:13,color:C.text}}>{(piloto.inicio||"--")+(piloto.fin?" - "+piloto.fin:"")}</div>
              <div style={{fontSize:10,color:C.textSub,fontWeight:700,textTransform:"uppercase",letterSpacing:"0.06em",marginTop:10,marginBottom:6}}>Equipos</div>
              <div style={{display:"flex",flexWrap:"wrap",gap:5}}>
                {(piloto.equipo||[]).length===0?<span style={{fontSize:12,color:C.textSub}}>Sin equipos adicionales</span>:(piloto.equipo||[]).map(e=>{const m=OWNER_META[e]||{bg:"#F1F5F9",text:"#334155",icon:"?"};return <span key={e} style={{display:"inline-flex",alignItems:"center",gap:4,background:m.bg,color:m.text,borderRadius:999,fontSize:11,fontWeight:600,padding:"2px 9px"}}>{m.icon+" "+e}</span>;})}
              </div>
            </div>
          </div>
        )}
      </div>
      <div style={{padding:"16px 28px",borderTop:"1px solid "+C.border,display:"flex",justifyContent:"space-between",alignItems:"center",flexShrink:0}}>
        <button onClick={onClose} style={{background:"transparent",color:C.textSub,border:"1px solid "+C.border,borderRadius:8,padding:"9px 20px",fontSize:13,fontWeight:600,cursor:"pointer"}}>Cerrar</button>
        <div style={{display:"flex",gap:10}}>
          {!editMode ? (
            <>
              <button onClick={()=>setEditMode(true)} style={{background:"transparent",color:C.blue,border:"1px solid "+C.blue,borderRadius:8,padding:"9px 16px",fontSize:13,fontWeight:700,cursor:"pointer"}}>Editar ficha</button>
              <button onClick={()=>setConfirm("rechazar")} style={{background:"transparent",color:C.red,border:"1px solid "+C.red,borderRadius:8,padding:"9px 16px",fontSize:13,fontWeight:700,cursor:"pointer"}}>Rechazar</button>
              <button onClick={()=>setConfirm("aprobar")} style={{background:C.green,color:"#FFFFFF",border:"none",borderRadius:8,padding:"9px 20px",fontSize:13,fontWeight:700,cursor:"pointer"}}>Aprobar</button>
            </>
          ) : (
            <>
              <button onClick={()=>setEditMode(false)} style={{background:"transparent",color:C.textSub,border:"1px solid "+C.border,borderRadius:8,padding:"9px 16px",fontSize:13,fontWeight:600,cursor:"pointer"}}>Cancelar</button>
              <button onClick={()=>{onUpdate(piloto.id,{objetivo:ef.objetivo,kpis:ef.kpis,hipotesis:ef.hipotesis,alcance:ef.alcance,inicio:ef.inicio,fin:ef.fin,equipo:ef.equipo});setEditMode(false);}} style={{background:C.navy,color:"#FFFFFF",border:"none",borderRadius:8,padding:"9px 20px",fontSize:13,fontWeight:700,cursor:"pointer"}}>Guardar cambios</button>
            </>
          )}
        </div>
      </div>
    </CenteredModal>
  );
}

function CierrePanel({piloto,onClose,onSave}) {
  const [step,setStep]=useState(1);
  const [saved,setSaved]=useState(false);
  const [resultado,setResultado]=useState("");
  const [decisionTomar,setDecisionTomar]=useState("");
  const [validacionHipotesis,setValidacionHipotesis]=useState("");
  const [objetivos,setObjetivos]=useState("");
  const [alcanceConseguido,setAlcanceConseguido]=useState("");
  const [resumen,setResumen]=useState("");

  const RESULTADOS=[
    {key:"ok",label:"Cierre OK",bg:"#F0FDF4",border:"#86EFAC",text:"#166534"},
    {key:"ko",label:"Cierre KO",bg:"#FEF2F2",border:"#FCA5A5",text:"#991B1B"},
    {key:"cancel",label:"Cancelado",bg:"#F9FAFB",border:"#D1D5DB",text:"#374151"},
  ];
  const DECISIONES=["Escalar","Descartar","Hacer otro piloto","Finalizar"];
  const HIPOTESIS_OPTS=["Si","No","Parcialmente"];
  const pct=Math.round((step/2)*100);
  const canGO=resultado==="ok";
  const canNOGO=resultado==="ko";
  const canCANCEL=resultado==="cancel";

  const handleSave=(tipo)=>{
    setSaved(true);
    const fecha=new Date().toLocaleDateString("es-ES");
    const cd={tipo,fecha,resultado,decision:decisionTomar,validacionHipotesis,objetivos,alcanceConseguido,resumen};
    setTimeout(()=>{onSave(piloto.id,tipo,cd);onClose();},1400);
  };

  return (
    <CenteredModal onClose={onClose} width={720}>
      <div style={{background:C.navy,padding:"20px 24px 0",flexShrink:0}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:16}}>
          <div>
            <div style={{fontSize:11,color:"rgba(255,255,255,0.55)",fontWeight:600,marginBottom:4}}>{"Cierre de piloto - #"+piloto.id+" - Paso "+step+" de 2"}</div>
            <div style={{fontSize:17,fontWeight:800,color:"#FFFFFF"}}>{piloto.nombre}</div>
          </div>
          <button onClick={onClose} style={{background:"rgba(255,255,255,0.12)",border:"none",color:"#FFFFFF",borderRadius:8,width:30,height:30,fontSize:16,cursor:"pointer"}}>X</button>
        </div>
        <div style={{display:"flex"}}>
          {["Resultados","Analisis y resumen"].map((s,i)=>{
            const active=step===i+1,done=step>i+1;
            return <div key={s} style={{flex:1,textAlign:"center",paddingBottom:12,borderBottom:"3px solid "+(active?"#FFFFFF":done?"rgba(255,255,255,0.45)":"transparent")}}><div style={{fontSize:10,fontWeight:700,color:active?"#FFFFFF":done?"rgba(255,255,255,0.65)":"rgba(255,255,255,0.3)",textTransform:"uppercase",letterSpacing:"0.05em"}}>{(done?"ok ":"")+s}</div></div>;
          })}
        </div>
      </div>
      <div style={{height:4,background:"#E2E8F0",flexShrink:0}}><div style={{width:pct+"%",height:4,background:"linear-gradient(90deg,"+C.navy+","+C.blue+")",transition:"width 0.3s"}}/></div>
      <div style={{flex:1,overflowY:"auto",padding:"24px"}}>
        {saved ? (
          <div style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:16,padding:"40px 0"}}>
            <div style={{fontSize:16,fontWeight:800,color:C.navy}}>Cierre registrado correctamente</div>
          </div>
        ) : step===1 ? (
          <div style={{display:"flex",flexDirection:"column",gap:20}}>
            <div>
              <Label required>Resultado del piloto</Label>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:12,marginTop:6}}>
                {RESULTADOS.map(r=>(
                  <button key={r.key} onClick={()=>setResultado(r.key)} style={{background:resultado===r.key?r.bg:C.bgCard,border:"2px solid "+(resultado===r.key?r.border:C.border),borderRadius:12,padding:"16px 12px",cursor:"pointer",display:"flex",flexDirection:"column",alignItems:"center",gap:8}}>
                    <span style={{fontSize:13,fontWeight:800,color:resultado===r.key?r.text:C.textSub}}>{r.label}</span>
                    {resultado===r.key&&<span style={{fontSize:10,background:r.border+"66",color:r.text,borderRadius:999,padding:"2px 8px",fontWeight:700}}>Seleccionado</span>}
                  </button>
                ))}
              </div>
            </div>
            <div>
              <Label required>Decision a tomar</Label>
              <div style={{display:"flex",flexWrap:"wrap",gap:8,marginTop:6}}>
                {DECISIONES.map(d=>(
                  <button key={d} onClick={()=>setDecisionTomar(d)} style={{background:decisionTomar===d?C.navy:C.bgCard,color:decisionTomar===d?"#FFFFFF":C.textSub,border:"1px solid "+(decisionTomar===d?C.navy:C.border),borderRadius:999,fontSize:13,fontWeight:600,padding:"7px 18px",cursor:"pointer"}}>{d}</button>
                ))}
              </div>
            </div>
            <div>
              <Label>Validacion de hipotesis</Label>
              <div style={{fontSize:12,color:C.textSub,marginBottom:8,fontStyle:"italic"}}>Se cumplio la hipotesis inicial planteada en la ficha del piloto?</div>
              {piloto.hipotesis&&(
                <div style={{background:"#F8FAFC",border:"1px solid "+C.border,borderRadius:8,padding:"10px 14px",marginBottom:10}}>
                  <div style={{fontSize:10,color:C.textSub,fontWeight:700,textTransform:"uppercase",letterSpacing:"0.05em",marginBottom:4}}>Hipotesis definida</div>
                  <div style={{fontSize:13,color:C.textSub,lineHeight:1.5}}>{piloto.hipotesis}</div>
                </div>
              )}
              <div style={{display:"flex",gap:10}}>
                {HIPOTESIS_OPTS.map(o=>(
                  <button key={o} onClick={()=>setValidacionHipotesis(o)} style={{flex:1,background:validacionHipotesis===o?(o==="Si"?"#F0FDF4":o==="No"?"#FEF2F2":"#FFFBEB"):C.bgCard,color:validacionHipotesis===o?(o==="Si"?"#166534":o==="No"?"#991B1B":"#92400E"):C.textSub,border:"1.5px solid "+(validacionHipotesis===o?(o==="Si"?"#86EFAC":o==="No"?"#FCA5A5":"#FDE68A"):C.border),borderRadius:10,padding:"12px",cursor:"pointer",fontSize:13,fontWeight:700}}>{o}</button>
                ))}
              </div>
            </div>
          </div>
        ) : (
          <div style={{display:"flex",flexDirection:"column",gap:20}}>
            <div>
              <Label>Consecucion de objetivos</Label>
              <div style={{fontSize:12,color:C.textSub,marginBottom:8,fontStyle:"italic"}}>Se lograron los objetivos cuantificables?</div>
              <TextArea value={objetivos} onChange={setObjetivos} placeholder="Describe los objetivos conseguidos y en que medida se alcanzaron..." rows={4}/>
            </div>
            <div>
              <Label>Alcance</Label>
              <div style={{fontSize:12,color:C.textSub,marginBottom:8,fontStyle:"italic"}}>Se pudo probar todo lo definido en el alcance del piloto o hubo que recortar?</div>
              {piloto.alcance&&(
                <div style={{background:"#F8FAFC",border:"1px solid "+C.border,borderRadius:8,padding:"10px 14px",marginBottom:10}}>
                  <div style={{fontSize:10,color:C.textSub,fontWeight:700,textTransform:"uppercase",letterSpacing:"0.05em",marginBottom:4}}>Alcance definido en la ficha</div>
                  <div style={{fontSize:13,color:C.textSub,lineHeight:1.5}}>{piloto.alcance}</div>
                </div>
              )}
              <TextArea value={alcanceConseguido} onChange={setAlcanceConseguido} placeholder="Justifica el alcance conseguido vs el planificado..." rows={3}/>
            </div>
            <div>
              <Label>Resumen ejecutivo</Label>
              <TextArea value={resumen} onChange={setResumen} placeholder="Escribe un resumen ejecutivo del piloto para presentar a direccion..." rows={4}/>
            </div>
          </div>
        )}
      </div>
      {!saved&&(
        <div style={{padding:"16px 24px",borderTop:"1px solid "+C.border,display:"flex",justifyContent:"space-between",alignItems:"center",gap:12,flexShrink:0}}>
          <button onClick={step===1?onClose:()=>setStep(1)} style={{background:"transparent",color:C.textSub,border:"1px solid "+C.border,borderRadius:8,padding:"9px 20px",fontSize:13,fontWeight:600,cursor:"pointer"}}>{step===1?"Cancelar":"Anterior"}</button>
          {step===1 ? (
            <button onClick={()=>{if(resultado)setStep(2);}} style={{background:resultado?C.blue:"#E2E8F0",color:resultado?"#FFFFFF":C.textSub,border:"none",borderRadius:8,padding:"9px 24px",fontSize:13,fontWeight:700,cursor:resultado?"pointer":"not-allowed"}}>Siguiente</button>
          ) : (
            <div style={{display:"flex",gap:10}}>
              <button onClick={()=>handleSave("OK")} disabled={!canGO} style={{background:canGO?"#166534":"#E2E8F0",color:canGO?"#FFFFFF":C.textSub,border:"none",borderRadius:8,padding:"9px 20px",fontSize:13,fontWeight:700,cursor:canGO?"pointer":"not-allowed",opacity:canGO?1:0.4}}>GO</button>
              <button onClick={()=>handleSave("KO")} disabled={!canNOGO} style={{background:canNOGO?"#991B1B":"#E2E8F0",color:canNOGO?"#FFFFFF":C.textSub,border:"none",borderRadius:8,padding:"9px 20px",fontSize:13,fontWeight:700,cursor:canNOGO?"pointer":"not-allowed",opacity:canNOGO?1:0.4}}>NO GO</button>
              <button onClick={()=>handleSave("CANCEL")} disabled={!canCANCEL} style={{background:canCANCEL?"#374151":"#E2E8F0",color:canCANCEL?"#FFFFFF":C.textSub,border:"none",borderRadius:8,padding:"9px 20px",fontSize:13,fontWeight:700,cursor:canCANCEL?"pointer":"not-allowed",opacity:canCANCEL?1:0.4}}>CANCELADO</button>
            </div>
          )}
        </div>
      )}
    </CenteredModal>
  );
}

function NuevoPilotoPanel({onClose,onSave}) {
  const [step,setStep]=useState(1);
  const [form,setForm]=useState(EMPTY_FORM);
  const [errors,setErrors]=useState({});
  const [saved,setSaved]=useState(false);
  const [instSearch,setInstSearch]=useState("");
  const [instOpen,setInstOpen]=useState(false);
  const instRef=useRef(null);
  useEffect(()=>{
    const h=e=>{if(instRef.current&&!instRef.current.contains(e.target))setInstOpen(false);};
    document.addEventListener("mousedown",h);
    return ()=>document.removeEventListener("mousedown",h);
  },[]);
  const set=(k,v)=>setForm(f=>({...f,[k]:v}));
  const toggleInst=inst=>set("instituciones",form.instituciones.includes(inst)?form.instituciones.filter(x=>x!==inst):[...form.instituciones,inst]);
  const toggleEquipo=e=>set("equipo",form.equipo.includes(e)?form.equipo.filter(x=>x!==e):[...form.equipo,e]);
  const STEPS=["Identificacion","Objetivos","Equipo y fechas"];
  const validate=()=>{
    const e={};
    if(step===1){if(!form.nombre.trim())e.nombre="Requerido";if(!form.owner)e.owner="Requerido";if(!form.instituciones.length)e.instituciones="Selecciona al menos una";}
    if(step===2){if(!form.objetivo.trim())e.objetivo="Requerido";if(!form.hipotesis.trim())e.hipotesis="Requerido";if(!form.alcance.trim())e.alcance="Requerido";if(!form.kpis.trim())e.kpis="Requerido";}
    if(step===3){if(!form.inicio)e.inicio="Requerido";if(!form.fin)e.fin="Requerido";}
    setErrors(e);return Object.keys(e).length===0;
  };
  const handleSave=()=>{if(!validate())return;setSaved(true);setTimeout(()=>{onSave(form);onClose();},1400);};
  const filteredInst=INSTITUCIONES_ALL.filter(i=>i.toLowerCase().includes(instSearch.toLowerCase()));
  const pctStep=Math.round((step/STEPS.length)*100);
  const Err=({f})=>errors[f]?<div style={{fontSize:11,color:"#EF4444",marginTop:4}}>{errors[f]}</div>:null;
  return (
    <CenteredModal onClose={onClose} width={720}>
      <div style={{background:C.navy,padding:"20px 24px 0",flexShrink:0}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:16}}>
          <div>
            <div style={{fontSize:11,color:"rgba(255,255,255,0.55)",fontWeight:600,marginBottom:4}}>{"Nueva ficha - Paso "+step+" de "+STEPS.length}</div>
            <div style={{fontSize:17,fontWeight:800,color:"#FFFFFF"}}>Alta de Piloto de Innovacion</div>
          </div>
          <button onClick={onClose} style={{background:"rgba(255,255,255,0.12)",border:"none",color:"#FFFFFF",borderRadius:8,width:30,height:30,fontSize:16,cursor:"pointer"}}>X</button>
        </div>
        <div style={{display:"flex"}}>
          {STEPS.map((s,i)=>{const active=step===i+1,done=step>i+1;return <div key={s} style={{flex:1,textAlign:"center",paddingBottom:12,borderBottom:"3px solid "+(active?"#FFFFFF":done?"rgba(255,255,255,0.45)":"transparent")}}><div style={{fontSize:10,fontWeight:700,color:active?"#FFFFFF":done?"rgba(255,255,255,0.65)":"rgba(255,255,255,0.3)",textTransform:"uppercase",letterSpacing:"0.05em"}}>{(done?"ok ":"")+s}</div></div>;})}
        </div>
      </div>
      <div style={{height:4,background:"#E2E8F0",flexShrink:0}}><div style={{width:pctStep+"%",height:4,background:"linear-gradient(90deg,"+C.navy+","+C.blue+")",transition:"width 0.3s"}}/></div>
      <div style={{flex:1,overflowY:"auto",padding:"24px"}}>
        {saved ? (
          <div style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:16,padding:"40px 0"}}>
            <div style={{fontSize:16,fontWeight:800,color:C.navy}}>Piloto creado!</div>
            <div style={{fontSize:13,color:C.textSub,textAlign:"center"}}>La ficha esta pendiente de aprobacion en el proximo comite.</div>
          </div>
        ) : (
          <div style={{display:"flex",flexDirection:"column",gap:18}}>
            {step===1&&(<>
              <div style={{background:"#EFF6FF",border:"1px solid #BFDBFE",borderRadius:10,padding:"12px 16px",fontSize:13,color:"#1E40AF"}}>Completa la informacion basica del piloto.</div>
              <div><Label required>Nombre del piloto</Label><Input value={form.nombre} onChange={v=>set("nombre",v)} placeholder="Ej. Concertacion IA WH"/><Err f="nombre"/></div>
              <div>
                <Label required>Owner</Label>
                <div style={{display:"flex",flexWrap:"wrap",gap:8,marginTop:4}}>
                  {OWNERS_LIST.map(o=>{const m=OWNER_META[o]||{bg:"#F1F5F9",text:"#334155",icon:"?"};return <button key={o} onClick={()=>set("owner",o)} style={{display:"inline-flex",alignItems:"center",gap:6,background:form.owner===o?m.bg:C.bgCard,color:form.owner===o?m.text:C.textSub,border:"1.5px solid "+(form.owner===o?m.text+"66":C.border),borderRadius:999,fontSize:12,fontWeight:700,padding:"6px 14px",cursor:"pointer"}}><span>{m.icon}</span>{o}</button>;})}
                </div>
                <Err f="owner"/>
              </div>
              <div>
                <Label required>Institucion piloto</Label>
                {form.instituciones.length>0&&<div style={{display:"flex",flexWrap:"wrap",gap:6,marginBottom:8}}>{form.instituciones.map(inst=><span key={inst} style={{display:"inline-flex",alignItems:"center",gap:5,background:"#EFF6FF",color:"#1E40AF",border:"1px solid #BFDBFE",borderRadius:999,fontSize:12,fontWeight:600,padding:"3px 10px"}}>{inst}<span onMouseDown={e=>{e.preventDefault();toggleInst(inst);}} style={{cursor:"pointer",fontSize:13,fontWeight:800,marginLeft:2}}>x</span></span>)}</div>}
                <div ref={instRef} style={{position:"relative"}}>
                  <div onClick={()=>setInstOpen(o=>!o)} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"9px 12px",border:"1px solid "+(instOpen?C.blue:C.border),borderRadius:8,cursor:"pointer",background:C.bgCard,fontSize:13,color:C.textSub}}>
                    <span>{form.instituciones.length?(form.instituciones.length+" seleccionada"+(form.instituciones.length>1?"s":"")):"Selecciona instituciones..."}</span>
                    <span>{instOpen?"v":">"}</span>
                  </div>
                  {instOpen&&<div style={{position:"absolute",top:"calc(100% + 4px)",left:0,right:0,background:C.bgCard,border:"1px solid "+C.border,borderRadius:10,boxShadow:"0 12px 32px rgba(0,0,0,0.18)",zIndex:2000,overflow:"hidden"}}>
                    <div style={{padding:"8px"}}><input autoFocus value={instSearch} onChange={e=>setInstSearch(e.target.value)} placeholder="Buscar..." style={{width:"100%",padding:"7px 10px",fontSize:13,border:"1px solid "+C.border,borderRadius:6,outline:"none",boxSizing:"border-box"}}/></div>
                    <div style={{maxHeight:200,overflowY:"auto"}}>{filteredInst.map(inst=><div key={inst} onMouseDown={e=>{e.preventDefault();toggleInst(inst);}} style={{display:"flex",alignItems:"center",gap:10,padding:"8px 14px",cursor:"pointer",background:form.instituciones.includes(inst)?"#EFF6FF":"transparent",borderBottom:"1px solid "+C.border}}><div style={{width:16,height:16,borderRadius:4,border:"2px solid "+(form.instituciones.includes(inst)?C.blue:C.border),background:form.instituciones.includes(inst)?C.blue:"transparent",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>{form.instituciones.includes(inst)&&<span style={{color:"#fff",fontSize:10,fontWeight:800}}>v</span>}</div><span style={{fontSize:13,color:form.instituciones.includes(inst)?C.blue:C.text}}>{inst}</span></div>)}</div>
                  </div>}
                </div>
                <Err f="instituciones"/>
              </div>
            </>)}
            {step===2&&(<>
              <div><Label required>Objetivo principal</Label><TextArea value={form.objetivo} onChange={v=>set("objetivo",v)} placeholder="Que se quiere conseguir?" rows={3}/><Err f="objetivo"/></div>
              <div><Label required>Hipotesis a validar</Label><TextArea value={form.hipotesis} onChange={v=>set("hipotesis",v)} placeholder="Si implementamos X esperamos Y..." rows={3}/><Err f="hipotesis"/></div>
              <div><Label required>Alcance del piloto</Label><TextArea value={form.alcance} onChange={v=>set("alcance",v)} placeholder="Define que se incluye y que queda fuera..." rows={3}/><Err f="alcance"/></div>
              <div><Label required>Metricas y criterios de exito</Label><TextArea value={form.kpis} onChange={v=>set("kpis",v)} placeholder="Ej. Ratio CONT/CON mayor 15%..." rows={3}/><Err f="kpis"/></div>
            </>)}
            {step===3&&(<>
              <div>
                <Label>Equipos participantes</Label>
                <div style={{display:"flex",flexWrap:"wrap",gap:8,marginTop:4}}>
                  {OWNERS_LIST.filter(o=>o!==form.owner).map(o=>{const m=OWNER_META[o]||{bg:"#F1F5F9",text:"#334155",icon:"?"};const active=form.equipo.includes(o);return <button key={o} onClick={()=>toggleEquipo(o)} style={{display:"inline-flex",alignItems:"center",gap:5,background:active?m.bg:C.bgCard,color:active?m.text:C.textSub,border:"1px solid "+(active?m.text+"44":C.border),borderRadius:999,fontSize:12,fontWeight:600,padding:"4px 12px",cursor:"pointer"}}><span>{m.icon}</span>{o}</button>;})}
                </div>
              </div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
                <div><Label required>Fecha inicio</Label><Input type="date" value={form.inicio} onChange={v=>set("inicio",v)}/><Err f="inicio"/></div>
                <div><Label required>Fecha fin prevista</Label><Input type="date" value={form.fin} onChange={v=>set("fin",v)}/><Err f="fin"/></div>
              </div>
              {form.nombre&&<div style={{background:"#F8FAFC",border:"1px solid "+C.border,borderRadius:10,padding:"16px"}}>
                <div style={{fontSize:11,color:C.textSub,fontWeight:700,textTransform:"uppercase",letterSpacing:"0.05em",marginBottom:12}}>Vista previa</div>
                <div style={{fontSize:15,fontWeight:800,color:C.navy,marginBottom:8}}>{form.nombre}</div>
                <div style={{display:"flex",gap:6,flexWrap:"wrap",marginBottom:10}}>
                  <span style={{background:"#FFF7ED",color:"#C2410C",borderRadius:999,fontSize:11,fontWeight:700,padding:"2px 10px"}}>Pendiente aprobacion</span>
                  {form.owner&&<span style={{background:OWNER_META[form.owner]?.bg,color:OWNER_META[form.owner]?.text,borderRadius:999,fontSize:11,fontWeight:700,padding:"2px 10px"}}>{(OWNER_META[form.owner]?.icon||"")+" "+form.owner}</span>}
                </div>
                {form.instituciones.length>0&&<div style={{fontSize:12,color:C.textSub}}>{form.instituciones.join(", ")}</div>}
              </div>}
            </>)}
          </div>
        )}
      </div>
      {!saved&&<div style={{padding:"16px 24px",borderTop:"1px solid "+C.border,display:"flex",justifyContent:"space-between",gap:12,flexShrink:0}}>
        <button onClick={step===1?onClose:()=>setStep(s=>s-1)} style={{background:"transparent",color:C.textSub,border:"1px solid "+C.border,borderRadius:8,padding:"9px 20px",fontSize:13,fontWeight:600,cursor:"pointer"}}>{step===1?"Cancelar":"Anterior"}</button>
        {step<3?<button onClick={()=>{if(validate()){setInstOpen(false);setStep(s=>s+1);}}} style={{background:C.blue,color:"#FFFFFF",border:"none",borderRadius:8,padding:"9px 24px",fontSize:13,fontWeight:700,cursor:"pointer"}}>Siguiente</button>
        :<button onClick={handleSave} style={{background:C.navy,color:"#FFFFFF",border:"none",borderRadius:8,padding:"9px 24px",fontSize:13,fontWeight:700,cursor:"pointer"}}>Enviar al comite</button>}
      </div>}
    </CenteredModal>
  );
}

const VIEWS=["Dashboard","Seguimiento"];

export default function App() {
  const [view,setView]=useState("Dashboard");
  const [filtroEstado,setFiltroEstado]=useState("Todos");
  const [filtroOwner,setFiltroOwner]=useState("Todos");
  const [detalle,setDetalle]=useState(null);
  const [fichaPopup,setFichaPopup]=useState(null);
  const [cierre,setCierre]=useState(null);
  const [informe,setInforme]=useState(null);
  const [showNuevo,setShowNuevo]=useState(false);
  const [pilotos,setPilotos]=useState([]);
  const [dbReady,setDbReady]=useState(false);

  useEffect(()=>{
    let interval: any;
    async function load() {
      try {
        let data = await dbGet();
        if (data.length === 0) {
          await dbSave(PILOTOS_INIT);
          data = PILOTOS_INIT;
        }
        data.sort((a:any,b:any)=>a.id-b.id);
        setPilotos(data);
        setDbReady(true);
      } catch(e) {
        console.error("DB error:", e);
        setPilotos(PILOTOS_INIT);
        setDbReady(true);
      }
    }
    load();
    interval = setInterval(load, 8000);
    return ()=>clearInterval(interval);
  },[]);

  const handleOpenDetail=p=>{
    if(p.estado==="Pendiente aprobacion") setFichaPopup(p);
    else setDetalle(p);
  };

  const handleUpdate=async (id,fields)=>{
    const now=new Date();
    const fecha=now.toLocaleDateString("es-ES")+" "+now.toLocaleTimeString("es-ES",{hour:"2-digit",minute:"2-digit"});
    const piloto=pilotos.find(p=>p.id===id);
    const entrada={fecha,cambio:"Estado: "+(fields.estado||"sin cambio")+". Next steps: "+(fields.nextSteps||"-")};
    const updated={...piloto,...fields,ultimoUpdate:now.toLocaleDateString("es-ES"),historial:[...(piloto.historial||[]),entrada]};
    const newPilotos=pilotos.map(p=>p.id===id?updated:p);
    setPilotos(newPilotos);
    await dbSave(newPilotos);
    setDetalle(prev=>prev&&prev.id===id?updated:prev);
    setFichaPopup(prev=>prev&&prev.id===id?updated:prev);
  };

  const handleAprobar=async id=>{
    const today=new Date().toLocaleDateString("es-ES");
    const updated=pilotos.map(p=>p.id===id?{...p,estado:"Analisis",nextSteps:"Aprobado en comite - pendiente inicio",ultimoUpdate:today}:p);
    setPilotos(updated);
    await dbSave(updated);
  };

  const handleRechazar=async id=>{
    const today=new Date().toLocaleDateString("es-ES");
    const updated=pilotos.map(p=>p.id===id?{...p,estado:"Rechazado Comite",ultimoUpdate:today}:p);
    setPilotos(updated);
    await dbSave(updated);
  };

  const handleSaveNuevo=async form=>{
    const newId=pilotos.length>0?Math.max(...pilotos.map(p=>p.id))+1:1;
    const iso2es=d=>d?d.split("-").reverse().join("/"):"";
    const newPiloto={id:newId,nombre:form.nombre,agrupador:"",institucion:form.instituciones.join(", "),estado:"Pendiente aprobacion",owner:form.owner,nextSteps:"Pendiente de aprobacion en comite",objetivo:form.objetivo,hipotesis:form.hipotesis,alcance:form.alcance,kpis:form.kpis,inicio:iso2es(form.inicio),fin:iso2es(form.fin),equipo:form.equipo,cierre:null,ultimoUpdate:null,historial:[]};
    const updated=[...pilotos,newPiloto];
    setPilotos(updated);
    await dbSave(updated);
  };

  const handleSaveCierre=async (id,tipo,cd)=>{
    const nuevoEstado=tipo==="OK"?"Cierre - OK":tipo==="KO"?"Cierre - KO":"Cancelado";
    const updated=pilotos.map(p=>p.id===id?{...p,estado:nuevoEstado,cierre:cd}:p);
    setPilotos(updated);
    await dbSave(updated);
    setDetalle(prev=>prev&&prev.id===id?{...prev,estado:nuevoEstado,cierre:cd}:prev);
    setCierre(null);
  };

  const filtered=pilotos.filter(p=>(filtroEstado==="Todos"||p.estado===filtroEstado)&&(filtroOwner==="Todos"||p.owner===filtroOwner));

  const cnt={
    pendiente:pilotos.filter(p=>p.estado==="Pendiente aprobacion").length,
    analisis:pilotos.filter(p=>p.estado==="Analisis").length,
    desarrollo:pilotos.filter(p=>p.estado==="Desarrollo").length,
    evaluacion:pilotos.filter(p=>p.estado==="Evaluacion").length,
    ok:pilotos.filter(p=>p.estado==="Cierre - OK").length,
    ko:pilotos.filter(p=>p.estado==="Cierre - KO").length,
    standby:pilotos.filter(p=>p.estado==="Cierre - Stand By").length,
  };

  const porOwner=OWNERS_LIST.map(o=>({
    name:o,
    total:pilotos.filter(p=>p.owner===o).length,
    activos:pilotos.filter(p=>p.owner===o&&["Analisis","Desarrollo","Evaluacion"].includes(p.estado)).length,
  })).filter(x=>x.total>0);

  if(!dbReady) return (
    <div style={{display:"flex",alignItems:"center",justifyContent:"center",minHeight:"100vh",background:"#F0F4F8",flexDirection:"column",gap:16}}>
      <div style={{width:48,height:48,border:"4px solid #E2E8F0",borderTop:"4px solid #007BFF",borderRadius:"50%",animation:"spin 0.8s linear infinite"}}/>
      <div style={{fontSize:14,color:"#6B7280",fontWeight:600}}>Conectando con la base de datos...</div>
      <style>{`@keyframes spin{to{transform:rotate(360deg)}}`}</style>
    </div>
  );

  return (
    <div style={{background:C.bgPage,minHeight:"100vh",fontFamily:"'Inter','Segoe UI',system-ui,sans-serif"}}>
      <div style={{background:C.navy,padding:"0 24px"}}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",paddingTop:18,paddingBottom:14}}>
          <div style={{display:"flex",alignItems:"center",gap:14}}>
            <div style={{width:48,height:48,flexShrink:0}}>
              <img src="data:image/png;base64," alt="Grupo Planeta" style={{width:48,height:48,objectFit:"contain"}}/>
            </div>
            <div>
              <div style={{fontSize:18,fontWeight:800,color:"#FFFFFF",letterSpacing:"-0.01em"}}>Pilotos de Innovacion</div>
              <div style={{fontSize:12,color:"rgba(255,255,255,0.6)",fontWeight:500}}>Planeta Formacion y Universidades - PMO v2</div>
            </div>
          </div>
          <div style={{display:"flex",alignItems:"center",gap:12}}>
            <div style={{background:"rgba(255,255,255,0.1)",border:"1px solid rgba(255,255,255,0.2)",borderRadius:10,padding:"8px 16px",textAlign:"right"}}>
              <div style={{fontSize:10,color:"rgba(255,255,255,0.6)",fontWeight:600,textTransform:"uppercase",letterSpacing:"0.05em"}}>Proximo comite</div>
              <div style={{fontSize:13,color:"#FFFFFF",fontWeight:700}}>{proximoMiercoles()}</div>
            </div>
            <button onClick={()=>setShowNuevo(true)} style={{background:C.blue,color:"#FFFFFF",border:"none",borderRadius:10,padding:"10px 18px",fontSize:13,fontWeight:700,cursor:"pointer",display:"flex",alignItems:"center",gap:7,whiteSpace:"nowrap",boxShadow:"0 2px 8px rgba(0,123,255,0.35)"}}>
              <span style={{fontSize:18,lineHeight:1}}>+</span> Nuevo piloto
            </button>
          </div>
        </div>
        <div style={{display:"flex",gap:4}}>
          {VIEWS.map(v=><button key={v} onClick={()=>setView(v)} style={{background:view===v?"#FFFFFF":"transparent",color:view===v?C.navy:"rgba(255,255,255,0.7)",border:"none",borderRadius:"8px 8px 0 0",padding:"10px 22px",fontSize:13,fontWeight:700,cursor:"pointer"}}>{v}</button>)}
        </div>
      </div>

      <div style={{padding:24}}>
        {view==="Dashboard"&&(
          <div>
            <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(120px,1fr))",gap:12,marginBottom:24}}>
              {[
                {label:"Pte. aprobacion",value:cnt.pendiente,accent:"#F97316"},
                {label:"Analisis",value:cnt.analisis,accent:"#3B82F6"},
                {label:"Desarrollo",value:cnt.desarrollo,accent:"#007BFF"},
                {label:"Evaluacion",value:cnt.evaluacion,accent:"#F59E0B"},
                {label:"Cierre OK",value:cnt.ok,accent:"#22C55E"},
                {label:"Cierre KO",value:cnt.ko,accent:"#EF4444"},
                {label:"Stand By",value:cnt.standby,accent:"#9CA3AF"},
                {label:"Cancelado",value:pilotos.filter(p=>p.estado==="Cancelado").length,accent:"#EC4899"},
              ].map(t=>(
                <div key={t.label} style={{background:C.bgCard,border:"1px solid "+C.border,borderRadius:12,padding:"14px 16px",borderTop:"3px solid "+t.accent}}>
                  <div style={{display:"flex",alignItems:"center",gap:5,marginBottom:6}}>
                    <span style={{width:8,height:8,borderRadius:"50%",background:t.accent,flexShrink:0}}/>
                    <span style={{fontSize:11,color:C.textSub,fontWeight:600}}>{t.label}</span>
                  </div>
                  <div style={{fontSize:28,fontWeight:800,color:C.navy}}>{t.value}</div>
                </div>
              ))}
            </div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16,marginBottom:24}}>
              <div style={{background:C.bgCard,border:"1px solid "+C.border,borderRadius:12,padding:"18px 20px"}}>
                <div style={{fontSize:13,fontWeight:700,color:C.navy,marginBottom:14}}>Pilotos por institucion</div>
                {INSTITUCIONES.map(inst=>{
                  const total=pilotos.filter(p=>p.institucion===inst).length;
                  const activos=pilotos.filter(p=>p.institucion===inst&&["Analisis","Desarrollo","Evaluacion"].includes(p.estado)).length;
                  if(!total)return null;
                  return (
                    <div key={inst} style={{display:"flex",alignItems:"center",gap:10,marginBottom:9}}>
                      <div style={{fontSize:12,color:C.textSub,width:72,flexShrink:0}}>{inst}</div>
                      <div style={{flex:1,background:"#F1F5F9",borderRadius:999,height:14,position:"relative",overflow:"hidden"}}>
                        <div style={{position:"absolute",left:0,top:0,height:14,width:Math.round((total/pilotos.length)*100)+"%",background:C.blue+"33",borderRadius:999}}/>
                        <div style={{position:"absolute",left:0,top:0,height:14,width:Math.round((activos/pilotos.length)*100)+"%",background:C.blue,borderRadius:999}}/>
                      </div>
                      <div style={{fontSize:12,fontWeight:700,color:C.navy,width:22,textAlign:"right"}}>{total}</div>
                    </div>
                  );
                })}
              </div>
              <div style={{background:C.bgCard,border:"1px solid "+C.border,borderRadius:12,padding:"18px 20px"}}>
                <div style={{fontSize:13,fontWeight:700,color:C.navy,marginBottom:14}}>Pilotos por owner</div>
                {porOwner.map(o=>{
                  const om=OWNER_META[o.name]||{icon:"",text:"#334155"};
                  return (
                    <div key={o.name} style={{display:"flex",alignItems:"center",gap:10,marginBottom:9}}>
                      <div style={{display:"flex",alignItems:"center",gap:5,width:80,flexShrink:0}}><span>{om.icon}</span><span style={{fontSize:12,color:C.textSub}}>{o.name}</span></div>
                      <div style={{flex:1,background:"#F1F5F9",borderRadius:999,height:14,position:"relative",overflow:"hidden"}}>
                        <div style={{position:"absolute",left:0,top:0,height:14,width:Math.round((o.total/pilotos.length)*100)+"%",background:om.text+"33",borderRadius:999}}/>
                        <div style={{position:"absolute",left:0,top:0,height:14,width:Math.round((o.activos/pilotos.length)*100)+"%",background:om.text,borderRadius:999}}/>
                      </div>
                      <div style={{fontSize:12,fontWeight:700,color:C.navy,width:22,textAlign:"right"}}>{o.total}</div>
                    </div>
                  );
                })}
              </div>
            </div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16}}>
              <div style={{background:C.bgCard,border:"1px solid "+C.border,borderRadius:12,padding:"18px 20px"}}>
                <div style={{fontSize:13,fontWeight:700,color:C.navy,marginBottom:14}}>Proximos vencimientos</div>
                {pilotos.filter(p=>p.fin&&["Analisis","Desarrollo","Evaluacion"].includes(p.estado))
                  .map(p=>{const parts=p.fin.split("/");const diff=Math.ceil((new Date(parts[2]+"-"+parts[1]+"-"+parts[0])-new Date())/(1000*60*60*24));return {...p,diff};})
                  .sort((a,b)=>a.diff-b.diff).slice(0,5)
                  .map(p=>(
                    <div key={p.id} onClick={()=>handleOpenDetail(p)} style={{display:"flex",alignItems:"center",gap:10,padding:"9px 0",borderBottom:"1px solid "+C.border,cursor:"pointer"}}>
                      <div style={{flex:1,minWidth:0}}>
                        <div style={{fontSize:13,fontWeight:700,color:C.navy,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{p.nombre}</div>
                        <div style={{fontSize:11,color:C.textSub}}>{p.owner}</div>
                      </div>
                      <div style={{textAlign:"right",flexShrink:0}}>
                        <div style={{fontSize:12,fontWeight:700,color:p.diff<0||p.diff<=14?"#DC2626":p.diff<=30?"#D97706":"#16A34A"}}>{p.diff<0?"Vencido":p.diff===0?"Hoy":p.diff+"d"}</div>
                        <div style={{fontSize:10,color:C.textSub}}>{p.fin}</div>
                      </div>
                      <span style={{width:8,height:8,borderRadius:"50%",background:p.diff<0||p.diff<=14?"#EF4444":p.diff<=30?"#F59E0B":"#22C55E",flexShrink:0}}/>
                    </div>
                  ))}
              </div>
              <div style={{background:C.bgCard,border:"1px solid "+C.border,borderRadius:12,padding:"18px 20px"}}>
                <div style={{fontSize:13,fontWeight:700,color:C.navy,marginBottom:14}}>Pendientes de actualizacion</div>
                {pilotos.filter(p=>["Analisis","Desarrollo","Evaluacion"].includes(p.estado)).slice(0,5).map(p=>{
                  const om=OWNER_META[p.owner]||{icon:"?"};
                  return (
                    <div key={p.id} onClick={()=>handleOpenDetail(p)} style={{display:"flex",alignItems:"center",gap:10,padding:"9px 0",borderBottom:"1px solid "+C.border,cursor:"pointer"}}>
                      <span style={{fontSize:16}}>{om.icon}</span>
                      <div style={{flex:1,minWidth:0}}>
                        <div style={{fontSize:13,fontWeight:700,color:C.navy,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{p.nombre}</div>
                        <div style={{fontSize:11,color:C.textSub}}>{p.owner}</div>
                      </div>
                      <div style={{fontSize:11,fontWeight:700,color:p.ultimoUpdate?"#16A34A":"#DC2626",flexShrink:0}}>{p.ultimoUpdate||"Sin actualizar"}</div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        )}

        {view==="Seguimiento"&&(
          <div>
            <div style={{background:C.bgCard,border:"1px solid "+C.border,borderRadius:12,padding:"16px 20px",marginBottom:16}}>
              <div style={{display:"flex",flexDirection:"column",gap:16}}>
                <div>
                  <div style={{fontSize:11,color:C.textSub,fontWeight:700,textTransform:"uppercase",letterSpacing:"0.05em",marginBottom:8}}>Estado</div>
                  <div style={{display:"flex",flexWrap:"wrap",gap:6}}>
                    {ESTADOS_FILTER.map(s=>{
                      const pend=s==="Pendiente aprobacion"?pilotos.filter(p=>p.estado==="Pendiente aprobacion").length:0;
                      return (
                        <div key={s} style={{position:"relative"}}>
                          <PillFilter label={ESTADO_DISPLAY[s]||s} active={filtroEstado===s} onClick={()=>setFiltroEstado(s)}/>
                          {pend>0&&<span style={{position:"absolute",top:-6,right:-6,background:"#EF4444",color:"#FFFFFF",borderRadius:999,fontSize:10,fontWeight:800,minWidth:16,height:16,display:"flex",alignItems:"center",justifyContent:"center",padding:"0 4px",pointerEvents:"none"}}>{pend}</span>}
                        </div>
                      );
                    })}
                  </div>
                </div>
                <div>
                  <div style={{fontSize:11,color:C.textSub,fontWeight:700,textTransform:"uppercase",letterSpacing:"0.05em",marginBottom:8}}>Owner</div>
                  <div style={{display:"flex",flexWrap:"wrap",gap:6}}>
                    {OWNERS_FILTER.map(o=><PillFilter key={o} label={o} active={filtroOwner===o} onClick={()=>setFiltroOwner(o)}/>)}
                  </div>
                </div>
              </div>
            </div>
            <div style={{fontSize:13,color:C.textSub,marginBottom:14}}>
              {"Mostrando "}<span style={{fontWeight:700,color:C.navy}}>{filtered.length}</span>{" pilotos"}
            </div>
            {filtered.length===0
              ?<div style={{background:C.bgCard,border:"1px solid "+C.border,borderRadius:12,padding:32,textAlign:"center",color:C.textSub}}>No hay pilotos con los filtros seleccionados.</div>
              :<div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(260px,1fr))",gap:16}}>
                {filtered.map(p=><PilotCard key={p.id} p={p} onDetail={handleOpenDetail} onInforme={p=>setInforme(p)}/>)}
              </div>
            }
          </div>
        )}
      </div>

      {detalle&&<DetailPanel piloto={detalle} onClose={()=>setDetalle(null)} onCerrar={p=>{setDetalle(null);setCierre(p);}} onUpdate={handleUpdate}/>}
      {fichaPopup&&<FichaPopup piloto={fichaPopup} onClose={()=>setFichaPopup(null)} onUpdate={handleUpdate} onAprobar={id=>{handleAprobar(id);setFichaPopup(null);}} onRechazar={id=>{handleRechazar(id);setFichaPopup(null);}}/>}
      {cierre&&<CierrePanel piloto={cierre} onClose={()=>setCierre(null)} onSave={handleSaveCierre}/>}
      {informe&&<InformeCierreModal piloto={informe} onClose={()=>setInforme(null)}/>}
      {showNuevo&&<NuevoPilotoPanel onClose={()=>setShowNuevo(false)} onSave={handleSaveNuevo}/>}
    </div>
  );
}
